const EVENTS = "[{\"cancelled\":false,\"description\":\"OBS!! påmeldingsfrist siden vi må vite hvor mange som kommer.\\n\\nSom sesongavslutning inviter vi til hyggelig kveld med pizza for alle medlemmer, trenere og styret. Det er fleksibel slutttid. De yngste kan hentes når det passer. De eldste går senest kl. 20:00. vel møtt. Osu! \\n\\nDet koster ingenting å være med.\\n\\nVi har glutenfri pizza, pizza med kun ost og saus og drikke (brus, saft, vann), så det skal være noe til alle :-)\\n\\nHvis du lure på om du skal ha på karatedrakt i kveld; Nei ikke GI (karatedrakt) i kveld.\\n\\nVelkommen! OSU!\\n\\nOBS!! påmeldingsfrist siden vi må vite hvor mange som kommer ellers blir det for lite eller for mye mat :-)\\n\",\"end\":\"2026-06-10T18:00:00Z\",\"id\":\"BC21E0A351614AFB89340E8B71ACEF62\",\"location\":\"Fritidsklubben Bærland skole Barliveien, Ålgård\",\"start\":\"2026-06-10T16:00:00Z\",\"title\":\"Sesongavslutning\"},{\"cancelled\":false,\"description\":\"Kl: 18:00 (oppmøte 17:30)\\nSted: Gymsalen på Bærland skole\\nPris:  Gradering - 200 Kr, \\nNy belte – 100 kr\\nPass – 100 kr.          (hvis du ikke har den mer)\\n\\nPris gradering etter påmeldingsfrist:   \\n      Gradering - 200 Kr,\\nNy belte – 100 kr\\n       Gebyr - 100 Kr\\nPåmeldingsfrist: Lørdag kl 23:59\\n                 \\nHusk å ta med \\n- Karatepass\\n- Drikkeflaske med vann\\n- Leggbeskyttere\\n- Handsker\\n- Syllabus \\n\\nGraderingen starter 18:00, så alle utøvere må ha varmet opp på forhånd. Møt opp 17:30. \\n\\nDet stilles krav til utstyr; ren drakt og riktig knyttet belte. \\n\\nOransje belte og oppover \\u003e Ta med hansker, leggbeskyttere og syllabussen, test deg selv og andre. Det forventes at dere kan alt til det beltet dere skal opp til, og alle foregående belter dere har tatt: Stillinger, slag, spark, blokkeringer og Kata, i tillegg til styrkekravene og Dojo Kun (budene på side 6 i syllabuss). \\n\\nSe på algardkarate.net/algardkarate/category/syllabus så finner du det du skal opp til \\n\\nHar du ikke syllabus eller mistet den, du kan kjøpe hos oss eller laste ned fra algardkarate.net/algardkarate/downloads/ KWO Syllabus 2010 full v 2.1.pdf\\n\\n\\n\\nLykke til!     Respekter alltid en Sihan!                                        \\n\\nOsu!\",\"end\":\"2026-06-08T18:00:00Z\",\"id\":\"F3E223B086734837A831828F926AAF5E\",\"location\":\"Bærland skole, Barliveien 5, Ålgård\",\"start\":\"2026-06-08T16:00:00Z\",\"title\":\"Gradering + ny belte\"},{\"cancelled\":false,\"description\":\"Kl: 18:00 (oppmøte 17:30)\\nSted: Gymsalen på Bærland skole\\nPris:  Gradering - 200 Kr, \\nPass – 100 kr.          (hvis du ikke har den mer)\\n\\nPris gradering etter påmeldingsfrist:   \\n      Gradering - 200 Kr,\\n       Gebyr - 100 Kr\\nPåmeldingsfrist: Lørdag kl 23:59\\n                 \\nHusk å ta med \\n- Karatepass\\n- Drikkeflaske med vann\\n- Leggbeskyttere\\n- Handsker\\n- Syllabus \\n\\nGraderingen starter 18:00, så alle utøvere må ha varmet opp på forhånd. Møt opp 17:30. \\n\\nDet stilles krav til utstyr; ren drakt og riktig knyttet belte. \\n\\nOransje belte og oppover \\u003e Ta med hansker, leggbeskyttere og syllabussen, test deg selv og andre. Det forventes at dere kan alt til det beltet dere skal opp til, og alle foregående belter dere har tatt: Stillinger, slag, spark, blokkeringer og Kata, i tillegg til styrkekravene og Dojo Kun (budene på side 6 i syllabuss). \\n\\nSe på algardkarate.net/algardkarate/category/syllabus så finner du det du skal opp til \\n\\nHar du ikke syllabus eller mistet den, du kan kjøpe hos oss eller laste ned fra algardkarate.net/algardkarate/downloads/ KWO Syllabus 2010 full v 2.1.pdf\\n\\n\\n\\nLykke til!     Respekter alltid en Sihan!                                        \\n\\nOsu!\",\"end\":\"2026-06-08T18:00:00Z\",\"id\":\"9ED143FF53BF4486BFF9264191CF6284\",\"location\":\"Bærland skole, Barliveien 5, Ålgård\",\"start\":\"2026-06-08T16:00:00Z\",\"title\":\"Gradering\"},{\"cancelled\":false,\"description\":\"Kl: 18:00 (oppmøte 17:30)\\nSted: Gymsalen på Bærland skole\\nPris:  Min første gradering: 400Kr \\ni pakken får du:\\n- oransje belte.   (100 kr)\\n- karatepass       (100 kr) \\n- kostnader for gradering. (200kr)\\nPåmeldingsfrist: Lørdag kl 23:59\\n\\nPris gradering etter påmeldingsfrist:   \\n       - Min første gradering: 400Kr \\n       - Gebyr - 100 Kr\\n         \\nOg husk å ta med drikkeflaske med vann\\n\\nGraderingen starter 18:00, så alle utøvere må ha varmet opp på forhånd. Møt opp 17:30. \\nSlutttid er sirka 19:30 siden det er mange utøvere  som skal graderes\\n\\nDet stilles krav til utstyr; ren drakt og riktig knyttet belte. \\n\\nGradering er å vise dine kunnskaper det du har lært gjennom trening og etter vel gjennomført gradering blir du belønnet med en ny grad.\\nPå vår webside finner du mer informasjon om hvilken belte som finnes https://www.algardkarate.net/algardkarate/belte/\\nHer finner du også video om hvordan belte skal knyttes.\\n\\nPå https://www.algardkarate.net/algardkarate/10-kyu-oransje-belte/  finner du det du skal vite om å gjennomføre gradering.\\nAlt dette har vi gått gjennom på trening flere ganger.\\n\\nSyllabus som vi bruker kan lastes ned her https://www.algardkarate.net/algardkarate/downloads/\\nMappe: Syllabus\\nDokument: KWO_Syllabus_2010 full_v-2-1.pdf\\n\\nhttps://drive.google.com/drive/folders/1KURHMkTBFPJP_HPl8ZeDddQX2BXp1GfI\\n\\n\\nFor å ikke forstyrre graderingen kan vi dessverre ikke ta imot tilskuere.\\n\\nLykke til og respekter alltid en Senpai!\\n                            \\n\\t\\t\\t\\t\\t\\t\\tOSU!\",\"end\":\"2026-06-08T18:00:00Z\",\"id\":\"8C1C111929444BBABA554373232970A4\",\"location\":\"Bærland skole, Barliveien 5, Ålgård\",\"start\":\"2026-06-08T16:00:00Z\",\"title\":\"Nybegynner gradering\"},{\"cancelled\":true,\"description\":\"Velkommen til karatetrening\\n\\nVi skal trene inne i gymsalen men hvis det er fint vær kan det hende vi trener ute.\\nÅlgård Karateklubb følger retningslinjene til Norges idrettsforbund og Kampsportforbundet. \\n\\n- Ta med drikkeflaske med vann.\\n- Det blir oppmøteregistrering i tilfelle det trengs smittesporing.\\n- Toalett kan brukes men helst gå på do før du kommer på trening.\\n- Vi trener i karatedrakt (Gi)\\n- Sett mobil i flymodus eller skru den av.\\n\\nOsu!\",\"end\":\"2026-05-25T18:00:00Z\",\"id\":\"0CED6603835C4033A6EACEFDA2946F56\",\"location\":\"Bærland skole\",\"start\":\"2026-05-25T17:00:00Z\",\"title\":\"Karate trening graderte\"},{\"cancelled\":true,\"description\":\"Hvilken oppgaver kan dere jobbe med:\\n- starte med oppvarming\\n- uttøying på slutten\\n- kata til 10 kyu\\n- korrigere stilling\\n- holde orden /disiplin i rekkene\",\"end\":\"2026-05-25T17:00:00Z\",\"id\":\"985240B667774BEEB178FE6D34E9A5C7\",\"location\":\"Bærland skole\",\"start\":\"2026-05-25T16:00:00Z\",\"title\":\"Hjelpetrener\"},{\"cancelled\":true,\"description\":\"Hvilken oppgaver kan dere jobbe med:\\n- starte med oppvarming\\n- uttøying på slutten\\n- kata til 10 kyu\\n- korrigere stilling\\n- holde orden /disiplin i rekkene\",\"end\":\"2026-04-06T17:00:00Z\",\"id\":\"05570AEC4D6B4901A7C3F2F966BD4C33\",\"location\":\"Bærland skole\",\"start\":\"2026-04-06T16:00:00Z\",\"title\":\"Hjelpetrener\"},{\"cancelled\":true,\"description\":\"Hvilken oppgaver kan dere jobbe med:\\n- starte med oppvarming\\n- uttøying på slutten\\n- kata til 10 kyu\\n- korrigere stilling\\n- holde orden /disiplin i rekkene\",\"end\":\"2026-04-01T17:00:00Z\",\"id\":\"0988BB7A7C6340B09BFCB88418C355D4\",\"location\":\"Bærland skole\",\"start\":\"2026-04-01T16:00:00Z\",\"title\":\"Hjelpetrener\"},{\"cancelled\":true,\"description\":\"Hvilken oppgaver kan dere jobbe med:\\n- starte med oppvarming\\n- uttøying på slutten\\n- kata til 10 kyu\\n- korrigere stilling\\n- holde orden /disiplin i rekkene\",\"end\":\"2026-03-30T17:00:00Z\",\"id\":\"805906FDC4774D8C90BE65FA5B6E2DFA\",\"location\":\"Bærland skole\",\"start\":\"2026-03-30T16:00:00Z\",\"title\":\"Hjelpetrener\"}]";

let currentDate = new Date();
let selectedDate = null;

const monthNames = ["JANUAR","FEBRUAR","MARS","APRIL","MAI","JUNI",
                    "JULI","AUGUST","SEPTEMBER","OKTOBER","NOVEMBER","DESEMBER"];
const norDays = ["SU","MO","TI","ON","TO","FR","LO"];

function pad(n) { return String(n).padStart(2, "0"); }
function toDateStr(d) { return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}`; }
function todayStr() { return toDateStr(new Date()); }

function buildCalendar(year, month) {
  document.getElementById("month-year").textContent = monthNames[month] + " " + year;
  const grid = document.getElementById("calendar-days");
  grid.innerHTML = "";

  const eventDates = new Set(EVENTS.map(e => e.start.slice(0, 10)));
  const firstDay = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const today = todayStr();

  for (let i = 0; i < firstDay; i++) {
    const b = document.createElement("div");
    b.className = "day-cell empty";
    grid.appendChild(b);
  }

  for (let d = 1; d <= daysInMonth; d++) {
    const ds = `${year}-${pad(month+1)}-${pad(d)}`;
    const cell = document.createElement("div");
    cell.className = "day-cell";
    cell.textContent = d;
    if (ds === today) cell.classList.add("today");
    if (eventDates.has(ds)) cell.classList.add("has-event");
    if (ds === selectedDate) cell.classList.add("selected");
    cell.addEventListener("click", () => {
      selectedDate = ds;
      buildCalendar(year, month);
      showEvents(ds);
    });
    grid.appendChild(cell);
  }
}

function showEvents(dateStr) {
  const list = document.getElementById("event-list");
  const dayEvents = EVENTS.filter(e => e.start.slice(0, 10) === dateStr);


  const dt = new Date(dateStr + "T12:00:00");
  const heading = dt.toLocaleDateString("no-NO", { weekday: "long", day: "numeric", month: "long" });
  const capHeading = heading.charAt(0).toUpperCase() + heading.slice(1);

  if (dayEvents.length === 0) {
    list.innerHTML = `
${capHeading}
Ingen treninger denne dagen.`;
    return;
  }

  list.innerHTML = `
${capHeading}` + dayEvents.map(e => {
    const start = new Date(e.start);
    const end = new Date(e.end);
    const timeStr = start.toLocaleTimeString("no-NO", {hour:"2-digit", minute:"2-digit"})
                  + "\u2013"
                  + end.toLocaleTimeString("no-NO", {hour:"2-digit", minute:"2-digit"});
    const cancelBadge = e.cancelled ? 'Avlyst' : "";
    const loc = e.location ? `
${e.location}` : "";
    const desc = e.description ? `
${e.description}` : "";
    return `





${e.title}${cancelBadge}
          ${timeStr}

        ${loc}${desc}
      `;
  }).join("");
}

document.getElementById("prev-month").addEventListener("click", () => {
  currentDate.setMonth(currentDate.getMonth() - 1);
  buildCalendar(currentDate.getFullYear(), currentDate.getMonth());
  if (selectedDate) showEvents(selectedDate);
});
document.getElementById("next-month").addEventListener("click", () => {
  currentDate.setMonth(currentDate.getMonth() + 1);
  buildCalendar(currentDate.getFullYear(), currentDate.getMonth());
  if (selectedDate) showEvents(selectedDate);
});


selectedDate = todayStr();
buildCalendar(currentDate.getFullYear(), currentDate.getMonth());
showEvents(selectedDate);
